// BAD: invalid signatures recover to address(0) and may still pass checks
// address signer = ecrecover(hash, v, r, s);
// require(signer == owners[tokenId]); // forged if owners[tokenId] is unset (0)

// GOOD (minimal): reject the zero sentinel explicitly
address signer = ecrecover(hash, v, r, s);
require(signer != address(0), "invalid signature");
require(signer == expectedSigner, "unauthorized");

// BEST: use OpenZeppelin ECDSA, which reverts on invalid and malleable signatures
import {ECDSA} from "@openzeppelin/contracts/utils/cryptography/ECDSA.sol";
import {MessageHashUtils} from "@openzeppelin/contracts/utils/cryptography/MessageHashUtils.sol";

function verify(bytes32 dataHash, bytes calldata signature) internal view {
    bytes32 digest = MessageHashUtils.toEthSignedMessageHash(dataHash);
    address signer = ECDSA.recover(digest, signature); // reverts on bad input
    require(signer == expectedSigner, "unauthorized");
}
